+  vi.resetModules();
+  try {
+    return await fn();
+  } finally {
+    if (prev === undefined) {
+      delete process.env.CLAWDBOT_STATE_DIR;
+    } else {
+      process.env.CLAWDBOT_STATE_DIR = prev;
+    }
+    vi.resetModules();
+  }
