+            configurable: {
+              config: "nope" as unknown as Record<string, unknown>,
+            },
+          },
+        },
+      },
+    });
+
+    expect(registry.plugins[0]?.status).toBe("error");
+    expect(registry.diagnostics.some((d) => d.level === "error")).toBe(true);
+  });
